+import { createHmac } from 'crypto';
+import { prisma } from '@/lib/prisma';
+
+export interface SolvencyPassportData {
+  orgId: string;
+  asOf: Date;
+  hcs: number;
+  scg: number;
+  residualEsUsd: number;
+}
+
+export interface SolvencyPassportReceipt {
+  orgId: string;
+  grade: 'A' | 'B' | 'C';
+  proof: string;
+  issuedAt: Date;
+  asOf: Date;
+  expiresAt: Date;
+}
+
+function calculateGrade(hcs: number, scg: number): 'A' | 'B' | 'C' {
+  if (hcs >= 80 && scg >= 75) return 'A';
+  if (hcs >= 60 && scg >= 50) return 'B';
+  return 'C';
+}
+
+function signData(data: SolvencyPassportData): string {
+  const secretKey = process.env.SOLVENCY_PASSPORT_SECRET || '';
+  if (!secretKey) {
+    throw new Error('SOLVENCY_PASSPORT_SECRET not configured');
+  }
+  const dataStr = JSON.stringify({
+    orgId: data.orgId,
+    asOf: data.asOf.toISOString(),
+    hcs: data.hcs,
+    scg: data.scg,
+    residualEsUsd: data.residualEsUsd,
+  });
+  return createHmac('sha256', secretKey).update(dataStr).digest('hex');
+}
+
+export async function issue(
+  orgId: string,
+  asOf?: Date
+): Promise<SolvencyPassportReceipt> {
+  const org = await prisma.org.findUnique({
+    where: { id: orgId },
+    include: { riskData: true },
+  });
+
+  if (!org) {
+    throw new Error('org_not_found');
+  }
+
+  if (!org.riskData) {
+    throw new Error('incomplete_risk_data');
+  }
+
+  if (
+    org.riskData.hcs == null ||
+    org.riskData.scg == null ||
+    org.riskData.residualEsUsd == null
+  ) {
+    throw new Error('incomplete_risk_data');
+  }
+
+  const asOfDate = asOf || new Date();
+  const issuedAtDate = new Date();
+  const expiresAtDate = new Date(asOfDate);
+  expiresAtDate.setDate(expiresAtDate.getDate() + 30);
+
+  const data: SolvencyPassportData = {
+    orgId,
+    asOf: asOfDate,
+    hcs: org.riskData.hcs,
+    scg: org.riskData.scg,
+    residualEsUsd: org.riskData.residualEsUsd,
+  };
+
+  const grade = calculateGrade(data.hcs, data.scg);
+  const proof = signData(data);
+
+  const receipt = await prisma.solvencyPassportReceipt.create({
+    data: {
+      orgId,
+      grade,
+      proof,
+      hcs: data.hcs,
+      scg: data.scg,
+      residualEsUsd: data.residualEsUsd,
+      issuedAt: issuedAtDate,
+      asOf: asOfDate,
+      expiresAt: expiresAtDate,
+    },
+  });
+
+  return toPublicReceipt(receipt);
+}
+
+export async function verify(
+  receipt: SolvencyPassportReceipt
+): Promise<{ valid: boolean; reason?: string }> {
+  try {
+    const now = new Date();
+    const expiresAt = new Date(receipt.expiresAt);
+    if (now > expiresAt) {
+      return { valid: false, reason: 'receipt_expired' };
+    }

+    const storedReceipt = await prisma.solvencyPassportReceipt.findFirst({
+      where: {
+        proof: receipt.proof,
+      },
+    });
+
+    if (!storedReceipt) {
+      return { valid: false, reason: 'tampering_detected' };
+    }
+
+    const data: SolvencyPassportData = {
+      orgId: storedReceipt.orgId,
+      asOf: storedReceipt.asOf,
+      hcs: storedReceipt.hcs,
+      scg: storedReceipt.scg,
+      residualEsUsd: storedReceipt.residualEsUsd,
+    };
+
+    const expectedProof = signData(data);
+    if (expectedProof !== receipt.proof) {
+      return { valid: false, reason: 'tampering_detected' };
+    }
+
+    return { valid: true };
+  } catch {
+    return { valid: false, reason: 'malformed_receipt' };
+  }
+}
+
+function toPublicReceipt(data: {
+  orgId: string;
+  grade: string;
+  proof: string;
+  issuedAt: Date;
+  asOf: Date;
+  expiresAt: Date;
+}): SolvencyPassportReceipt {
+  return {
+    orgId: data.orgId,
+    grade: data.grade as 'A' | 'B' | 'C',
+    proof: data.proof,
+    issuedAt: data.issuedAt,
+    asOf: data.asOf,
+    expiresAt: data.expiresAt,
+  };
+}
